def findValue(myList: list, num: int):
    """ Finds the positions of a number in a given list of int. """
    for idx, entry in enumerate(myList):
        if isinstance(entry, list):
            res = findValue(entry, num)
            if res is not None:
                return [idx] + res
        else:
            if entry == num:
                return [idx]
    return None

